#include<cstdio>
#include<vector>
#include<algorithm>
#include<cmath>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;struct node{int l,r,t,idx,lc;}Q[N];struct Nd{int p,u,v;}T[N];
std::vector<int> G[N];int n,m,q,a[N],idx[N<<1],ql[N],qr[N],cdt,tm=1,c[N],cnt[N],sc[N];int L,R,ct;LL Ans,ans[N],w[N];bool vis[N];
inline void dfs(const int &u,const int &fa=0){idx[ql[u]=++cdt]=u;for(int v: G[u])if(v!=fa)dfs(v,u);idx[qr[u]=++cdt]=u;}
inline void work(const int &p,const int &v)
{
	if(vis[p]){Ans-=w[cnt[c[p]]]*a[c[p]];--cnt[c[p]];Ans+=w[cnt[c[p]]]*a[c[p]];}c[p]=v;
	if(vis[p]){Ans-=w[cnt[c[p]]]*a[c[p]];++cnt[c[p]];Ans+=w[cnt[c[p]]]*a[c[p]];}
}
inline void tadd(){++ct;int p=T[ct].p,v=T[ct].v;work(p,v);}
inline void tmns(){int p=T[ct].p,v=T[ct].u;--ct;work(p,v);}
inline void ins(const int &p)
{	
	if(vis[p]){Ans-=w[cnt[c[p]]]*a[c[p]];--cnt[c[p]];Ans+=w[cnt[c[p]]]*a[c[p]];vis[p]=false;}
	else {Ans-=w[cnt[c[p]]]*a[c[p]];++cnt[c[p]];Ans+=w[cnt[c[p]]]*a[c[p]];vis[p]=true;}
//	printf("ins %d :: %lld , ",p,Ans);rep(1,m,i)printf("%d ",cnt[i]);puts("");
}
int top[N],siz[N],dep[N],mxs[N],fa[N];
inline void dfs1(const int &u,const int &f)
{
	siz[u]=1;int mx=0;dep[u]=dep[fa[u]=f]+1;
	for(int v: G[u])if(v!=f){dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
}
inline void dfs2(const int &u,const int &fa,const int &tp)
{
	top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
	for(int v:G[u])if(v!=fa&&v!=mxs[u])dfs2(v,u,v);
}
inline int LCA(int u,int v)
{
	while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];
	return dep[u] < dep[v] ? u : v ;
}
int main()
{
	n=read();m=read();int nq=read();rep(1,m,i)a[i]=read();rep(1,n,i)w[i]=w[i-1]+read();
	rep(2,n,i){int x=read(),y=read();G[x].push_back(y);G[y].push_back(x);} rep(1,n,i)c[i]=sc[i]=read();
	dfs(1);dfs1(1,0);dfs2(1,0,1);while(nq--)if(read())
	{
		int u=read(),v=read();++q;
		if(ql[u]>ql[v]){int tmp(u);u=v;v=tmp;}
		if(ql[u]<=ql[v]&&qr[v]<=qr[u])Q[q]=(node){ql[u],ql[v],tm,q,0};
		else Q[q]=(node){qr[u],ql[v],tm,q,LCA(u,v)};
	}
	else{int p=read(),v=read();T[++tm]=(Nd){p,sc[p],v};sc[p]=v;}
	int BK=pow((q+n)>>1,0.6666666);
	std::sort(Q+1,Q+q+1,[&](const node&x,const node&y){return (x.l/BK)==(y.l/BK)?((x.r/BK)==(y.r/BK)?x.t<y.t:x.r<y.r):x.l<y.l;});
//	rep(1,q,i)printf("%d :: [%d,%d,%d]\n",Q[i].idx,Q[i].l,Q[i].r,Q[i].t);
//	rep(1,cdt,i)printf("%d ",idx[i]);puts("");
	L=Q[1].l;R=Q[1].l-1;ct=1;rep(1,q,i)
	{
//		printf("%d :: \n",i);
		while(R<Q[i].r)ins(idx[++R]);while(L>Q[i].l)ins(idx[--L]);
		while(R>Q[i].r)ins(idx[R--]);while(L<Q[i].l)ins(idx[L++]);
		while(ct<Q[i].t)tadd();while(ct>Q[i].t)tmns();
		if(Q[i].lc)ins(Q[i].lc);ans[Q[i].idx]=Ans;if(Q[i].lc)ins(Q[i].lc);
	}
	rep(1,q,i)printf("%lld\n",ans[i]);
}
